using System.ComponentModel;
using System.Text.Json;
using System.Text.RegularExpressions;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search and page-fetching capabilities for the research agent.
/// Uses DuckDuckGo's instant-answer API for searches and raw HTTP for page fetching.
/// </summary>
public sealed class WebSearchTool(HttpClient httpClient)
{
    [Description("Search the web for information on a query. Returns relevant result snippets and URLs.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        try
        {
            var json = await httpClient.GetStringAsync(url);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            var abstractText = root.GetProperty("AbstractText").GetString();
            var abstractSource = root.GetProperty("AbstractSource").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();

            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"[{abstractSource}] {abstractText}\nURL: {abstractUrl}");
            }

            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(8))
                {
                    if (topic.TryGetProperty("Text", out var t) &&
                        topic.TryGetProperty("FirstURL", out var u))
                    {
                        var text = t.GetString();
                        var firstUrl = u.GetString();
                        if (!string.IsNullOrWhiteSpace(text))
                            results.Add($"- {text}\n  URL: {firstUrl}");
                    }
                }
            }

            return results.Count > 0
                ? string.Join("\n\n", results)
                : "No results found. Try rephrasing or using a more specific query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch and extract text content from a web page URL. Use this to read articles and gather detailed information.")]
    public async Task<string> FetchWebPage(
        [Description("The full URL of the web page to fetch")] string url)
    {
        try
        {
            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.Add("Accept", "text/html");

            using var response = await httpClient.SendAsync(request);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync();

            // Strip scripts, styles, and HTML tags to get plain text
            var text = Regex.Replace(html, @"<script[^>]*>.*?</script>", " ",
                RegexOptions.Singleline | RegexOptions.IgnoreCase);
            text = Regex.Replace(text, @"<style[^>]*>.*?</style>", " ",
                RegexOptions.Singleline | RegexOptions.IgnoreCase);
            text = Regex.Replace(text, @"<[^>]+>", " ");
            text = System.Net.WebUtility.HtmlDecode(text);
            text = Regex.Replace(text, @"\s+", " ").Trim();

            const int maxLength = 4000;
            if (text.Length > maxLength)
                text = text[..maxLength] + "\n... [truncated]";

            return string.IsNullOrWhiteSpace(text)
                ? "Could not extract meaningful text from the page."
                : text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }
}

using System.ComponentModel;

namespace ResearchAgent.Tools;

/// <summary>
/// In-memory note-taking tool that lets the agent record and retrieve research findings.
/// </summary>
public sealed class NoteTool
{
    private readonly List<string> _notes = [];

    [Description("Save a research note to record an important finding or piece of information.")]
    public string SaveNote(
        [Description("The content of the note to save")] string content)
    {
        _notes.Add(content);
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieve all saved research notes collected during this session.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        return string.Join("\n\n", _notes.Select((n, i) => $"--- Note #{i + 1} ---\n{n}"));
    }
}

