using System.ClientModel;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY");
if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.Error.WriteLine("Error: Set the OPENAI_API_KEY environment variable.");
    return 1;
}

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// --- Build tools ---
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
httpClient.Timeout = TimeSpan.FromSeconds(30);

var webSearch = new WebSearchTool(httpClient);
var noteTool = new NoteTool();

List<AITool> tools =
[
    AIFunctionFactory.Create(webSearch.SearchWeb),
    AIFunctionFactory.Create(webSearch.FetchWebPage),
    AIFunctionFactory.Create(noteTool.SaveNote),
    AIFunctionFactory.Create(noteTool.GetNotes),
];

// --- Build AI client (no auto function-invocation — we drive the loop for visibility) ---
using IChatClient client = new OpenAIClient(new ApiKeyCredential(apiKey))
    .GetChatClient(modelId)
    .AsIChatClient();

const string systemPrompt = """
    You are a research agent. Your job is to thoroughly research a topic provided by the user.

    Available tools:
      SearchWeb     – search the web for information
      FetchWebPage  – read the full text of a web page
      SaveNote      – record an important finding
      GetNotes      – retrieve all saved notes

    Workflow:
      1. Break the topic into key questions or subtopics.
      2. Search the web for each subtopic.
      3. Fetch promising pages for detailed information.
      4. Save important findings as notes (aim for at least 3 notes).
      5. Retrieve your notes, then write a comprehensive summary with source URLs.
    """;

// --- Interactive loop ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║        🔍 AI Research Agent          ║");
Console.WriteLine("╠══════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research, or      ║");
Console.WriteLine("║  type 'quit' to exit.               ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.Write("Research topic> ");
    var topic = Console.ReadLine()?.Trim();

    if (string.IsNullOrWhiteSpace(topic))
        continue;
    if (topic.Equals("quit", StringComparison.OrdinalIgnoreCase) ||
        topic.Equals("exit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.WriteLine($"\n🔬 Researching: {topic}\n");

    List<ChatMessage> messages =
    [
        new(ChatRole.System, systemPrompt),
        new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
    ];

    var options = new ChatOptions { Tools = tools };

    try
    {
        // Agent loop: keep calling the model until it stops issuing tool calls.
        const int maxIterations = 15;
        for (var iteration = 0; iteration < maxIterations; iteration++)
        {
            var response = await client.GetResponseAsync(messages, options);

            // Append the assistant's reply to the conversation history.
            messages.AddRange(response.Messages);

            // Collect any tool calls the model wants to make.
            var functionCalls = response.Messages
                .SelectMany(m => m.Contents)
                .OfType<FunctionCallContent>()
                .ToList();

            if (functionCalls.Count == 0)
            {
                // No tool calls — the model produced its final answer.
                Console.WriteLine(response.Text);
                break;
            }

            // Invoke each requested tool and feed results back.
            foreach (var call in functionCalls)
            {
                Console.WriteLine($"  🔧 {call.Name}({Truncate(call.Arguments)})");

                FunctionResultContent result;
                try
                {
                    result = await call.InvokeAsync();
                }
                catch (Exception ex)
                {
                    result = new FunctionResultContent(call.CallId, call.Name, $"Error: {ex.Message}");
                }

                messages.Add(new ChatMessage(ChatRole.Tool, [result]));
            }

            Console.WriteLine();
        }
    }
    catch (Exception ex)
    {
        Console.Error.WriteLine($"\n❌ Error: {ex.Message}\n");
    }

    Console.WriteLine();
}

Console.WriteLine("Goodbye!");
return 0;

// --- Helpers ---
static string Truncate(IReadOnlyDictionary<string, object?>? args, int maxLen = 80)
{
    if (args is null || args.Count == 0) return "";
    var text = string.Join(", ", args.Select(kv => $"{kv.Key}: {kv.Value}"));
    return text.Length <= maxLen ? text : text[..maxLen] + "…";
}

