1. using System.ClientModel;
2. using Microsoft.Extensions.AI;
3. using OpenAI;
4. using ResearchAgent.Tools;
5. 
6. // --- Configuration ---
7. var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY");
8. if (string.IsNullOrWhiteSpace(apiKey))
9. {
10.     Console.Error.WriteLine("Error: Set the OPENAI_API_KEY environment variable.");
11.     return 1;
12. }
13. 
14. var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
15. 
16. // --- Build tools ---
17. using var httpClient = new HttpClient();
18. httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
19. httpClient.Timeout = TimeSpan.FromSeconds(30);
20. 
21. var webSearch = new WebSearchTool(httpClient);
22. var noteTool = new NoteTool();
23. 
24. List<AITool> tools =
25. [
26.     AIFunctionFactory.Create(webSearch.SearchWeb),
27.     AIFunctionFactory.Create(webSearch.FetchWebPage),
28.     AIFunctionFactory.Create(noteTool.SaveNote),
29.     AIFunctionFactory.Create(noteTool.GetNotes),
30. ];
31. 
32. // --- Build AI client (no auto function-invocation — we drive the loop for visibility) ---
33. using IChatClient client = new OpenAIClient(new ApiKeyCredential(apiKey))
34.     .GetChatClient(modelId)
35.     .AsIChatClient();
36. 
37. const string systemPrompt = """
38.     You are a research agent. Your job is to thoroughly research a topic provided by the user.
39. 
40.     Available tools:
